  'pt': { text: "\ud83e\udd16 Ol\u00e1! Sou seu bot tutor de idiomas pessoal.\n\nVou te ajudar a aprender um novo idioma passo a passo \u2014 atrav\u00e9s de conversa\u00e7\u00e3o, gram\u00e1tica e vocabul\u00e1rio.", greeting: "Ol\u00e1" },
