const reply = $('Process Onboarding Response').item.json.content[0].text;
const match = reply.match(/LEVEL_RESULT:\s*([A-C][12])/i);
if (match) {
  const level = match[1].toUpperCase();
  return [{ json: { isLevelSet: true, level, reply: reply.replace(/LEVEL_RESULT:[^\n]*/i,'').trim() } }];
}
return [{ json: { isLevelSet: false, level: null, reply } }];

const tg = $('Telegram Trigger').item.json;
const msg = tg.message || tg.edited_message || {};
const cb = tg.callback_query || {};
const from = msg.from || cb.from || {};
const userId = from.id;
if (!userId) return [];
const langCode = (from.language_code || 'en').slice(0, 2).toLowerCase();
return [{
  json: {
    userId,
    username: from.username || null,
    firstName: from.first_name || 'User',
    langCode,
  }
}];

const historyRaw = $('Get History').item.json.value || '[]';
let history = [];
try { history = JSON.parse(historyRaw); } catch(e) { history = []; }

const userText = $('Telegram Trigger').item.json.message?.text || '';
history.push({ role: 'user', content: userText });

const assistantText = $('Onboarding Claude').item.json.content[0].text;
history.push({ role: 'assistant', content: assistantText });

return [{
  json: {
    content: [{ text: assistantText }],
    historyJson: JSON.stringify(history),
    userId: $('Router').item.json.userId
  }
}];

const text = $input.first().json.text || '';
const word = text.replace('/word ', '').trim();
const level = $input.first().json.level || 'A1';
const nativeLang = $input.first().json.nativeLang || 'ru';
const targetLang = $input.first().json.targetLang || 'en';

const LANG = { ru:'Russian',en:'English',es:'Spanish',zh:'Chinese',ar:'Arabic',
  pt:'Portuguese',fr:'French',de:'German',hi:'Hindi',ja:'Japanese',
  ko:'Korean',it:'Italian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',
  nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian' };
const nativeName = LANG[nativeLang] || nativeLang;
const targetName = LANG[targetLang] || targetLang;

const system = `You are an English teacher. The student's native language is ${nativeName} and they are learning ${targetName}. Level: ${level}.

Explain the word following this structure:
1. **[word]** — translation to ${nativeName}
2. Simple definition in ${targetName} (1 sentence)
3. Two examples with the word in **bold**:
   • ...
   • ...
4. 💡 Memory tip — in ${nativeName}

End with (in ${nativeName}): ask the student to compose their own sentence with the word.`;

return [{
  json: {
    ...$input.first().json,
    claudeBody: JSON.stringify({
      model: 'claude-haiku-4-5',
      max_tokens: 400,
      system: system,
      messages: [{ role: 'user', content: word }]
    })
  }
}];

const typedText = $('Router').item.json.text || '';
const voiceFileId = $('Router').item.json.voiceFileId || '';
const level = $('Router').item.json.level || 'A1';
const nativeLang = $('Router').item.json.nativeLang || 'ru';
const targetLang = $('Router').item.json.targetLang || 'en';
const userText = typedText.replace('/talk', '').trim();

const LANG = { ru:'Russian',en:'English',es:'Spanish',zh:'Chinese',ar:'Arabic',
  pt:'Portuguese',fr:'French',de:'German',hi:'Hindi',ja:'Japanese',
  ko:'Korean',it:'Italian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',
  nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian' };
const nativeName = LANG[nativeLang] || nativeLang;
const targetName = LANG[targetLang] || targetLang;

if (voiceFileId && !userText) {
  return [{ json: { ...$input.first().json, claudeBody: JSON.stringify({
    model: 'claude-haiku-4-5', max_tokens: 100,
    messages: [{ role: 'user', content: 'Say exactly: "🎤 Voice messages not supported yet. Please type your message!"' }]
  }) } }];
}

const system = `You are a ${targetName} language teacher. The student's native language is ${nativeName}. Level: ${level}.

Format every response:
1. Short reaction to what the student said — in ${nativeName} (1 sentence).
2. Gently correct any mistake if present: ❌ [as written] → ✅ [corrected] — no lengthy explanation.
3. Continue the conversation in ${targetName} (2-3 sentences appropriate for level ${level}).
4. Ask one question in ${targetName} to keep the dialogue going.

A1-A2: use simple words, add translations in parentheses for hard words.
B1-B2: fewer hints, natural conversation.
C1: communicate like a native speaker, minimal use of ${nativeName}.`;

const content = userText || 'Hello! Let\'s start talking.';

return [{ json: {
  ...$input.first().json,
  claudeBody: JSON.stringify({
    model: 'claude-haiku-4-5',
    max_tokens: 350,
    system: system,
    messages: [{ role: 'user', content: content }]
  })
} }];

const text = $('Telegram Trigger').item.json.message?.text || '';
const level = $('Router').item.json.level || 'A1';
const nativeLang = $('Router').item.json.nativeLang || 'ru';
const targetLang = $('Router').item.json.targetLang || 'en';

const LANG = { ru:'Russian',en:'English',es:'Spanish',zh:'Chinese',ar:'Arabic',
  pt:'Portuguese',fr:'French',de:'German',hi:'Hindi',ja:'Japanese',
  ko:'Korean',it:'Italian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',
  nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian' };
const nativeName = LANG[nativeLang] || nativeLang;
const targetName = LANG[targetLang] || targetLang;

const historyRaw = $('Get Grammar History').item.json.value || '[]';
let history = [];
try { history = JSON.parse(historyRaw); } catch(e) { history = []; }
if (history.length > 10) history = history.slice(-10);
history.push({ role: 'user', content: text });

const system = `You are a ${targetName} grammar coach. The student's native language is ${nativeName}. Level: ${level}.

Check grammar of ANY text the student sends. Never refuse. Never discuss content.

If correct:
✅ [1 sentence about the grammar rule — in ${nativeName}]

If incorrect:
❌ [original]
✅ [corrected]
💡 [explanation in ${nativeName}, 1-2 sentences]

Always end with a follow-up exercise in ${nativeName}, asking the student to write a complete sentence:
"[ask to compose a sentence freely in ${nativeName}]"

Never ask to fill in blanks like "He ___ (eat)". Always ask to compose a sentence freely.`;

return [{ json: {
  ...$input.first().json,
  grammarHistory: history,
  grammarHistoryJson: JSON.stringify(history),
  claudeBody: JSON.stringify({
    model: 'claude-haiku-4-5',
    max_tokens: 400,
    system: system,
    messages: history
  })
} }];

const item = $input.first().json;
const userId = $('Router').item.json.userId;
const firstName = $('Router').item.json.firstName;
const level = item.level || 'A1';
const reply = item.reply || '';

return [{ json: {
  ...item,
  levelResultBody: JSON.stringify({
    chat_id: userId,
    parse_mode: 'Markdown',
    text: '🎉 Отлично, ' + firstName + '!\n\nТвой уровень: *' + level + '*\n\n' + reply + '\n\nВыбери с чего начнём:',
    reply_markup: {
      inline_keyboard: [
        [{text: '📖 Слово', callback_data: 'menu_word'},{text: '✍️ Грамматика', callback_data: 'menu_grammar'}],
        [{text: '💬 Разговор', callback_data: 'menu_talk'},{text: '📊 Прогресс', callback_data: 'menu_progress'}],
        [{text: '🎯 Сменить уровень', callback_data: 'menu_level'}]
      ]
    }
  })
} }];

const assistantText = $('Claude Grammar').item.json.content[0].text;
const history = $('Prep Grammar Request').item.json.grammarHistory || [];
const updatedHistory = [...history, { role: 'assistant', content: assistantText }];

// Keep last 10 messages
const trimmed = updatedHistory.length > 10 ? updatedHistory.slice(-10) : updatedHistory;

return [{ json: {
  ...$input.first().json,
  content: [{ text: assistantText }],
  grammarHistoryJson: JSON.stringify(trimmed)
} }];

